Given('user selects Test Drive', async function () {
  console.log('📋 Selecting Test Drive from the Buying Tools menu');

  // Allow the Buying Tools drawer to fully open before searching for links.
  await this.page.waitForTimeout(1000);

  // The Hyundai PIP page main nav contains nav-card / dxo-selector-submenu-card
  // elements with "Book a test drive" text — these are NOT the Buying Tools drawer
  // items. We must find the link inside the sticky buying-tools drawer specifically,
  // and never click a nav-card or an element inside the primary navbar.
  const element = await this.page.evaluateHandle(() => {
    const isVisible = (el) => {
      const r = el.getBoundingClientRect();
      if (r.width === 0 || r.height === 0) return false;
      const s = getComputedStyle(el);
      return s.display !== 'none' && s.visibility !== 'hidden' && s.opacity !== '0';
    };

    const pattern = /test\s*drive|book\s*a\s*test\s*drive/i;
    const candidates = Array.from(document.querySelectorAll('a, button')).filter(el => {
      if (!pattern.test(el.textContent)) return false;
      if (!isVisible(el)) return false;
      // Exclude nav-card / submenu-card elements (main navbar dropdown links)
      if (/nav-card|submenu-card|submenu/i.test(el.className)) return false;
      // Exclude anything sitting inside the primary navigation
      if (el.closest('.navbar-menu, .primary-nav, [class*="navbar-menu"], [class*="primary-nav"]')) return false;
      return true;
    });
    return candidates[0] ?? null;
  });

  const el = element.asElement();
  if (!el) throw new Error('Could not find the Test Drive link in the Buying Tools drawer');

  await el.scrollIntoViewIfNeeded().catch(() => {});
  await this.page.waitForTimeout(300);

  try {
    await el.click({ timeout: 10000 });
  } catch {
    // The drawer link may still have a z-index overlay; dispatch a native click.
    await el.dispatchEvent('click');
  }

  this._activeModalHeader = 'Book a test drive';
  await this.page.waitForTimeout(1500);
  console.log('✅ Clicked Test Drive — BATD modal should now be opening');
});

Given('the user selects Powertrain from test data and clicks Next', async function () {
  // The loading step may find the generic "Test Drive" sheet before the specific
  // "Test Drive FIFO PCM2" sheet. Look for the FIFO-specific sheet first in allConfluenceData.
  const allData = this.allConfluenceData || {};
  const fifoKey = Object.keys(allData).find(k => /test drive fifo pcm2/i.test(k));
  const fifoRow = fifoKey ? (allData[fifoKey]?.[0] || {}) : {};
  const d = Object.keys(fifoRow).length ? fifoRow : (this.testDriveData?.[0] || {});

  // Confluence column header is "Powetrain" (typo — one 'r' missing); check both spellings
  const powertrain = d.Powertrain || d.Powetrain  ||
                     d.powertrain || d.powetrain  ||
                     d.Variant    || d.variant    || '';
  const postcode   = d['Your Location'] || d.Postcode || d.postcode || d['Set Location'] || '2000';

  console.log(`📋 testDriveData keys: [${Object.keys(d).join(', ')}]`);

  if (!powertrain) {
    throw new Error(`No Powertrain/Powetrain/Variant key found in test data — available keys: [${Object.keys(d).join(', ')}]`);
  }
  console.log(`📋 Powertrain: "${powertrain}", Postcode: "${postcode}"`);

  // Scope to the active BATD modal
  const header = this._activeModalHeader || 'Book a test drive';
  const modal = this.page.locator('.modal-wrapper').filter({
    has: this.page.locator(`.modal-header:has-text("${header}")`)
  }).first();

  // ── Step A: Wait for ModelOfinterest__c options to load (async, ~3-4s after modal opens) ──
  await this.page.locator('#test-drive-modal-model-pcm2 option').first()
    .waitFor({ state: 'attached', timeout: 15000 }).catch(() => {});

  // Dispatch change on model select to trigger FuelType__c options loading
  await this.page.evaluate(() => {
    const sel = document.querySelector('#test-drive-modal-model-pcm2');
    if (sel) sel.dispatchEvent(new Event('change', { bubbles: true }));
  });
  await this.page.waitForTimeout(1000);

  // ── Step B: Wait for FuelType__c options, then select the matching powertrain ──
  await this.page.locator('#test-drive-modal-energy-type-pcm2 option').first()
    .waitFor({ state: 'attached', timeout: 10000 }).catch(() => {});

  const energySelect = this.page.locator('#test-drive-modal-energy-type-pcm2');
  const energyOpts = await energySelect.locator('option').allTextContents().catch(() => []);
  console.log(`  Energy type options: [${energyOpts.join(', ')}]`);

  if (energyOpts.length > 0) {
    const match = energyOpts.find(o => o.trim().toLowerCase().includes(powertrain.toLowerCase()));
    if (match) {
      await energySelect.selectOption({ label: match.trim() });
      console.log(`✅ Selected powertrain: "${match.trim()}"`);
    } else {
      // Default to Petrol if test data value doesn't match any option
      const petrol = energyOpts.find(o => /petrol/i.test(o));
      const fallback = petrol || energyOpts.find(o => o.trim() && !/select|choose|--/i.test(o));
      if (fallback) await energySelect.selectOption({ label: fallback.trim() });
      console.log(`⚠️ "${powertrain}" not in [${energyOpts.join(', ')}] — selected "${fallback}"`);
    }
  }

  // ── Step C: Click Next → moves to "Set your location" step ──
  const nextBtn = modal.locator('button:has-text("Next"), button.next').first();
  await nextBtn.waitFor({ state: 'visible', timeout: 10000 });
  await nextBtn.click();
  await this.page.waitForTimeout(2000);

  // ── Step D: Handle "Set your location" step so Next becomes enabled ──
  // After clicking Next from the model/powertrain step, the modal shows "Set your location."
  // with a "Set location" button. Click it and fill the postcode so the Next button enables.
  // The actual Next click to advance to personal details is done by "the user clicks Next".
  const setLocationBtn = this.page.locator(
    'div[role="button"]:has-text("Set location"), button:has-text("Set location"), a:has-text("Set location")'
  ).first();

  if ((await setLocationBtn.count()) > 0 && await setLocationBtn.isVisible().catch(() => false)) {
    console.log(`📍 "Set your location" step detected — setting postcode: ${postcode}`);
    await setLocationBtn.scrollIntoViewIfNeeded().catch(() => {});
    await setLocationBtn.click({ timeout: 5000 });
    await this.page.waitForTimeout(1500);
    const { handleLocationModal } = await import('./commonHelpers.js');
    await handleLocationModal(this.page, postcode);
    await this.page.waitForTimeout(1000);
    console.log(`✅ Location set — Next button should now be enabled`);
  }

  console.log('✅ Model/Powertrain step complete — "the user clicks Next" will advance to personal details');
});

