When('the user selects Powertrain from test data', async function () {
  console.log('📋 Selecting Powertrain from test data (CAD scenario)');
  // Check contactDealerData first (FAD CAD scenario sets this to PCM2 data with a Powertrain column),
  // then fall back to testDriveData. Never use Variant as a powertrain fallback — that picks the
  // wrong value (e.g. "KONA Elite") from unrelated FIFO test data.
  const d = this.contactDealerData?.[0] || this.testDriveData?.[0] || {};
  const powertrain = d.Powertrain || d.Powetrain ||
                     d.powertrain || d.powetrain || '';

  if (!powertrain) {
    console.log('⚠️ No Powertrain/Powetrain in test data — skipping');
    return;
  }

  console.log(`📋 Powertrain from test data: "${powertrain}"`);

  // Scope to the active CAD modal
  const header = this._activeModalHeader || 'Contact a dealer';
  const modal = this.page.locator('.modal-wrapper').filter({
    has: this.page.locator(`.modal-header:has-text("${header}")`)
  }).first();

  // In the CAD form the powertrain/energy-type dropdown appears 2-3s AFTER model selection.
  // Use the same selectors as CPC_allFIFOs_auto.steps.js (line 415):
  const dropdown = modal.locator([
    '#cad-page-energy-type',
    'select[name="FuelType__c"]',
    'select[id*="energy" i]',
    'select[id*="powertrain" i]',
    'select[id*="fuel" i]',
  ].join(', ')).first();

  const visible = await dropdown.waitFor({ state: 'visible', timeout: 5000 }).then(() => true).catch(() => false);
  if (visible) {
    await dropdown.scrollIntoViewIfNeeded().catch(() => {});
    const options = await dropdown.locator('option').allTextContents();
    console.log(`  Powertrain dropdown options: [${options.join(', ')}]`);
    const match = options.find(o => o.trim().toLowerCase().includes(powertrain.toLowerCase()));
    if (match) {
      await dropdown.selectOption({ label: match.trim() });
      console.log(`✅ Selected powertrain: "${match.trim()}"`);
    } else if (options.length > 1) {
      const fallback = options.find(o => o.trim() && !/select|choose|--/i.test(o));
      if (fallback) {
        await dropdown.selectOption({ label: fallback.trim() });
        console.log(`⚠️ "${powertrain}" not found — selected fallback "${fallback}"`);
      }
    }
  } else {
    console.log(`ℹ️  Powertrain dropdown did not appear after model selection — skipping`);
  }
});
